const body = $input.first().json.body;

// Gera slug automático a partir do nome se não fornecido
const slug = body.slug || body.nome
  .toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

const id = `bairro-${slug}`;

return [{
  json: {
    mutations: [
      {
        createOrReplace: {
          _id: id,
          _type: 'bairro',
          nome: body.nome,
          slug: { _type: 'slug', current: slug },
          cidade: body.cidade || 'Rio de Janeiro',
          estado: body.estado || 'RJ',
          mercado: body.mercado || 'barra',
          regiao: body.regiao || '',
          zona: body.zona || '',
          ordem: body.ordem ? Number(body.ordem) : 99,
          bairroplanejado: false
        }
      }
    ]
  }
}];
